	 -- Oferta laboral - Notificació - Tancament vençut i estat no tancat
	('d3c1d5b7-f8d2-4df4-9f6b-2c63aa6b8e41', NOW(), NOW(), '1', '1', NULL, 'Notificació - Oferta amb tancament vençut sense estat tancada', 'Plantilla per notificar al responsable que l''oferta té la data de tancament de candidatures d''ahir i no està en estat tancada o similar.', 'Revisar oferta laboral: tancament de candidatures vençut - $stic_job_offers_name', 'Benvolgut/da $stic_job_offers_assigned_user_name,\r\n\r\nL''oferta laboral $stic_job_offers_name té la data de tancament de candidatures vençuda (ahir) i actualment està en estat $stic_job_offers_status.\r\n\r\nSi us plau, revisa l''oferta i actualitza''n l''estat si correspon: $sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id', '<p>Benvolgut/da $stic_job_offers_assigned_user_name,</p>\n<p>L''oferta laboral <strong>$stic_job_offers_name</strong> té la data de tancament de candidatures vençuda (ahir) i actualment està en estat <strong>$stic_job_offers_status</strong>.</p>\n<p>Si us plau, <a href="$sugarurl/index.php?module=stic_Job_Offers&action=DetailView&record=$stic_job_offers_id">revisa l''oferta</a> i actualitza''n l''estat si correspon.</p>', 0, '1', 0, 'notification'),
	-- Candidatura acceptada - Usuari assignat 
